SELECT COUNT(*) AS TOTAL FROM LATTES_P_EVENTO LPE JOIN LATTES_EVENTO LE ON LE.PK = LPE.FK_EVENTO JOIN SERVIDOR S ON S.PK_SIAPE = LPE.FK_SIAPE WHERE LE.ANO = 2024 AND LOWER(LPE.TIPO) LIKE LOWER('%apresenta%') AND LOWER(LPE.TIPO) LIKE LOWER('%oral%') AND LOWER(S.GENERO) = LOWER('masculino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('jat') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%matematica%'